  se <- sqrt( # Indentasi diberikan untuk memudahkan
    ( # pembacaan karena banyaknya tanda kurung
      (sd1^2) / (n1 - 1)
    ) + (
      (sd2^2) / (n2 - 1)
    )
  )
  z_hitung <- (xbar1 - xbar2) / se # menghitung nilai Z dari statistik
  return(z_hitung)
}

